const applyWorkedClasses = (
  root: HTMLElement | null,
  workedGroups: Set<string>,
  selectedGroups: Set<string>,
  focusGroup?: string | null,
  activeAreas?: string[]
) => {
  if (!root) return
  const hasFocusGroup = Boolean(focusGroup)
  const hasGroupFocus = hasFocusGroup && Boolean(root.querySelector(`[data-group="${focusGroup}"]`))
  const areaSet = new Set((activeAreas ?? []).map((area) => area.trim().toLowerCase()).filter(Boolean))

  const regions = root.querySelectorAll<HTMLElement>('[data-group]')
  regions.forEach((region) => {
    const group = region.getAttribute('data-group')
    if (!group) return
    const inWeek = workedGroups.has(group)
    const inSelected = selectedGroups.has(group)
    const isFocused = hasFocusGroup && group === focusGroup

    region.classList.toggle('worked-week', inWeek && !inSelected)
    region.classList.toggle('worked-selected', inSelected)
    region.classList.toggle('is-focused', isFocused)
    region.classList.toggle('is-dimmed', hasGroupFocus && !isFocused)
  })

  const areas = root.querySelectorAll<HTMLElement>('[data-area]')
  areas.forEach((area) => {
    const key = area.getAttribute('data-area')?.trim().toLowerCase()
    area.classList.toggle('is-active', Boolean(key && areaSet.has(key)))
  })

  root.classList.toggle('has-area-focus', areaSet.size > 0)
  root.classList.toggle('has-group-focus', hasGroupFocus)
}

export default function MuscleMapSvg({
  workedGroups,
  selectedGroups,
  view,
  focusGroup,
  activeAreas,
  compactFocus = false,
  showFocusCornerPoints = false,
  onToggle,
  onFlip,
}: MuscleMapSvgProps) {
  const frontRef = useRef<HTMLDivElement>(null)
  const backRef = useRef<HTMLDivElement>(null)
  const [frontAspect, setFrontAspect] = useState(FRONT_BASE.width / FRONT_BASE.height)
  const [backAspect, setBackAspect] = useState(BACK_BASE.width / BACK_BASE.height)
  const [frontWidthPx, setFrontWidthPx] = useState(0)
  const [backWidthPx, setBackWidthPx] = useState(0)

  const frontFocusCorners = getFocusCorners(focusGroup, 'front')
  const backFocusCorners = getFocusCorners(focusGroup, 'back')
  const frontMaxXSpan = getFocusMaxXSpan(focusGroup, 'front')
  const backMaxXSpan = getFocusMaxXSpan(focusGroup, 'back')

  const frontViewBox = compactFocus
    ? frontFocusCorners
      ? computeCornerFocusViewBox(FRONT_BASE, frontFocusCorners, frontAspect, frontWidthPx, frontMaxXSpan)
      : FRONT_VIEWBOX
    : FRONT_VIEWBOX
  const backViewBox = compactFocus
    ? backFocusCorners
      ? computeCornerFocusViewBox(BACK_BASE, backFocusCorners, backAspect, backWidthPx, backMaxXSpan)
      : BACK_VIEWBOX
    : BACK_VIEWBOX
  const frontImageHref = compactFocus ? FRONT_FOCUS_SVG_URL : FRONT_SVG_URL
  const backImageHref = compactFocus ? BACK_FOCUS_SVG_URL : BACK_SVG_URL

  useEffect(() => {
    if (!compactFocus) return
    const frontEl = frontRef.current
    const backEl = backRef.current
    const observers: ResizeObserver[] = []

    if (frontEl) {
      const obs = new ResizeObserver((entries) => {
        const entry = entries[0]
        if (!entry) return
        const width = entry.contentRect.width
        const height = entry.contentRect.height
        if (width > 0) setFrontWidthPx(width)
        if (width > 0 && height > 0) setFrontAspect(width / height)
      })
      obs.observe(frontEl)
      observers.push(obs)
    }

    if (backEl) {
      const obs = new ResizeObserver((entries) => {
        const entry = entries[0]
        if (!entry) return
        const width = entry.contentRect.width
        const height = entry.contentRect.height
        if (width > 0) setBackWidthPx(width)
        if (width > 0 && height > 0) setBackAspect(width / height)
      })
      obs.observe(backEl)
      observers.push(obs)
    }

    return () => observers.forEach((observer) => observer.disconnect())
  }, [compactFocus])

  useEffect(() => {
    applyWorkedClasses(frontRef.current, workedGroups, selectedGroups, focusGroup, activeAreas)
    applyWorkedClasses(backRef.current, workedGroups, selectedGroups, focusGroup, activeAreas)
  }, [workedGroups, selectedGroups, focusGroup, activeAreas])

  const findRegionGroup = (target: EventTarget | null) => {
    let node = target as Element | null
    while (node) {
      if (node instanceof Element && node.hasAttribute('data-group')) {
        return node.getAttribute('data-group')
      }
      node = node.parentElement
    }
    return null
  }

  const handleClick = (event: MouseEvent<HTMLElement>) => {
    const group = findRegionGroup(event.target)
    if (!group) {
      onFlip()
      return
    }
    onToggle(group)
  }

  return (
    <div className="muscle-map-grid" data-view={view}>
      <div className="map-panel" onClick={handleClick}>
        <div className="map-title-row">
          <p className="map-title">Front</p>
          <img
            className="map-rotate"
            src={`${import.meta.env.BASE_URL}rotate.svg`}
            alt=""
          />
        </div>
        <div
          ref={frontRef}
          className={`muscle-svg-frame ${compactFocus ? 'muscle-svg-frame-compact' : ''}`}
          role="img"
          aria-label="Front body map"
        >
          <svg className="muscle-map" viewBox={frontViewBox} aria-hidden="true">
            <defs>
              <clipPath id="muscle-clip-chest-front">
                <path d={CHEST_PATH} transform={CHEST_TRANSFORM} />
              </clipPath>
            </defs>
            <image
              href={frontImageHref}
              x="0"
              y="0"
              width="725"
              height="1145"
              className="muscle-image muscle-image-base"
              preserveAspectRatio="xMidYMid meet"
            />
            {focusGroup === 'Chest' ? (
              <g clipPath="url(#muscle-clip-chest-front)">
                <image
                  href={frontImageHref}
                  x="0"
                  y="0"
                  width="725"
                  height="1145"
                  className="muscle-image muscle-image-focus"
                  preserveAspectRatio="xMidYMid meet"
                />
              </g>
            ) : null}
            <g className="muscle-region" data-group="Chest" transform={CHEST_TRANSFORM}>
              <path d={CHEST_PATH} />
            </g>
            <g className="muscle-area-region" data-area="chest-upper" transform={CHEST_AREA_UPPER_TRANSFORM}>
              <path d={CHEST_AREA_UPPER_PATH} />
            </g>
            <g className="muscle-area-region" data-area="chest-mid" transform={CHEST_AREA_MID_TRANSFORM}>
              <path d={CHEST_AREA_MID_PATH} />
            </g>
            <g className="muscle-area-region" data-area="chest-lower" transform={CHEST_AREA_LOWER_TRANSFORM}>
              <path d={CHEST_AREA_LOWER_PATH} />
            </g>
            <g className="muscle-region" data-group="Biceps" transform={BICEPS_TRANSFORM}>
              <path d={BICEPS_PATH_LEFT} />
              <path d={BICEPS_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="biceps-longhead" transform={BICEPS_AREA_FRONT_LONGHEAD_TRANSFORM}>
              <path d={BICEPS_AREA_FRONT_LONGHEAD_PATH} />
              <path d={BICEPS_AREA_FRONT_LONGHEAD_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="biceps-shorthead" transform={BICEPS_AREA_FRONT_SHORTHEAD_TRANSFORM}>
              <path d={BICEPS_AREA_FRONT_SHORTHEAD_PATH} />
              <path d={BICEPS_AREA_FRONT_SHORTHEAD_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="biceps-brachialis" transform={BICEPS_AREA_FRONT_BRACHIALIS_TRANSFORM}>
              <path d={BICEPS_AREA_FRONT_BRACHIALIS_PATH} />
              <path d={BICEPS_AREA_FRONT_BRACHIALIS_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Forearms" transform={FOREARMS_FRONT_TRANSFORM}>
              <path d={FOREARMS_FRONT_PATH_LEFT} />
              <path d={FOREARMS_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Triceps" transform={TRICEPS_TRANSFORM}>
              <path d={TRICEPS_PATH_LEFT} />
              <path d={TRICEPS_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="triceps-inner" transform={TRICEPS_AREA_FRONT_INNER_TRANSFORM}>
              <path d={TRICEPS_AREA_FRONT_INNER_PATH} />
              <path d={TRICEPS_AREA_FRONT_INNER_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="triceps-medial" transform={TRICEPS_AREA_FRONT_MEDIAL_TRANSFORM}>
              <path d={TRICEPS_AREA_FRONT_MEDIAL_PATH} />
              <path d={TRICEPS_AREA_FRONT_MEDIAL_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Shoulder" transform={SHOULDER_FRONT_TRANSFORM}>
              <path d={SHOULDER_FRONT_PATH_LEFT} />
              <path d={SHOULDER_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="shoulder-front" transform={SHOULDER_AREA_FRONT_FRONT_TRANSFORM}>
              <path d={SHOULDER_AREA_FRONT_FRONT_PATH} />
              <path d={SHOULDER_AREA_FRONT_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="shoulder-medial" transform={SHOULDER_AREA_FRONT_MEDIAL_TRANSFORM}>
              <path d={SHOULDER_AREA_FRONT_MEDIAL_PATH} />
              <path d={SHOULDER_AREA_FRONT_MEDIAL_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Back" transform={BACK_MUSCLES_FRONT_TRANSFORM}>
              <path d={BACK_MUSCLES_FRONT_PATH} />
              <path d={BACK_MUSCLES_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Core" transform={CORE_TRANSFORM}>
              <path d={CORE_PATH} />
            </g>
            <g className="muscle-region" data-group="Legs" transform={LEGS_FRONT_TRANSFORM}>
              <path d={LEGS_FRONT_PATH_LEFT} />
              <path d={LEGS_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="legs-quads" transform={LEGS_FRONT_TRANSFORM}>
              <path d={LEGS_FRONT_PATH_LEFT} />
              <path d={LEGS_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="legs-adductor" transform={LEGS_AREA_FRONT_ADDUCTOR_TRANSFORM}>
              <path d={LEGS_AREA_FRONT_ADDUCTOR_PATH_LEFT} />
            </g>
            <g className="muscle-area-region" data-area="legs-calves" transform={LEGS_AREA_FRONT_CALVES_TRANSFORM}>
              <path d={LEGS_FRONT_PATH_LEFT} />
              <path d={LEGS_FRONT_PATH_RIGHT} />
            </g>
            {showFocusCornerPoints && frontFocusCorners ? (
              <g className="focus-corner-points">
                <circle cx={frontFocusCorners.topLeft.x} cy={frontFocusCorners.topLeft.y} r="8" />
                <circle cx={frontFocusCorners.topRight.x} cy={frontFocusCorners.topRight.y} r="8" />
                <circle cx={frontFocusCorners.bottomLeft.x} cy={frontFocusCorners.bottomLeft.y} r="8" />
                <circle cx={frontFocusCorners.bottomRight.x} cy={frontFocusCorners.bottomRight.y} r="8" />
              </g>
            ) : null}
          </svg>
        </div>
      </div>

      <div className="map-panel" onClick={handleClick}>
        <div className="map-title-row">
          <p className="map-title">Back</p>
          <img
            className="map-rotate"
            src={`${import.meta.env.BASE_URL}rotate.svg`}
            alt=""
          />
        </div>
        <div
          ref={backRef}
          className="muscle-svg-frame"
          role="img"
          aria-label="Back body map"
        >
          <svg className="muscle-map" viewBox={backViewBox} aria-hidden="true">
            <image
              href={backImageHref}
              x="0"
              y="0"
              width="731"
              height="1135"
              className="muscle-image muscle-image-base"
              preserveAspectRatio="xMidYMid meet"
            />
            <g className="muscle-region" data-group="Back" transform={BACK_MUSCLES_TRANSFORM}>
              <path d={BACK_MUSCLES_PATH} />
            </g>
            <g className="muscle-area-region" data-area="back-lats" transform={BACK_AREA_LATS_TRANSFORM}>
              <path d={BACK_AREA_LATS_PATH} />
            </g>
            <g className="muscle-area-region" data-area="back-traps" transform={BACK_AREA_TRAPS_TRANSFORM}>
              <path d={BACK_AREA_TRAPS_PATH} />
            </g>
            <g className="muscle-area-region" data-area="back-rhomboids" transform={BACK_AREA_RHOMBOIDS_TRANSFORM}>
              <path d={BACK_AREA_RHOMBOIDS_PATH} />
            </g>
            <g className="muscle-area-region" data-area="back-erectors" transform={BACK_AREA_ERECTORS_TRANSFORM}>
              <path d={BACK_AREA_ERECTORS_PATH} />
            </g>
            <g className="muscle-region" data-group="Shoulder" transform={SHOULDER_BACK_TRANSFORM}>
              <path d={SHOULDER_BACK_PATH_LEFT} />
              <path d={SHOULDER_BACK_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="shoulder-front" transform={SHOULDER_AREA_BACK_FRONT_TRANSFORM}>
              <path d={SHOULDER_AREA_BACK_FRONT_PATH} />
              <path d={SHOULDER_AREA_BACK_FRONT_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="shoulder-medial" transform={SHOULDER_AREA_BACK_MEDIAL_TRANSFORM}>
              <path d={SHOULDER_AREA_BACK_MEDIAL_PATH} />
              <path d={SHOULDER_AREA_BACK_MEDIAL_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="shoulder-rear" transform={SHOULDER_AREA_BACK_REAR_TRANSFORM}>
              <path d={SHOULDER_AREA_BACK_REAR_PATH} />
              <path d={SHOULDER_AREA_BACK_REAR_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Biceps" transform={BICEPS_BACK_TRANSFORM}>
              <path d={BICEPS_BACK_PATH_LEFT} />
              <path d={BICEPS_BACK_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="biceps-longhead" transform={BICEPS_AREA_BACK_LONGHEAD_TRANSFORM}>
              <path d={BICEPS_AREA_BACK_LONGHEAD_PATH} />
              <path d={BICEPS_AREA_BACK_LONGHEAD_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="biceps-brachialis" transform={BICEPS_AREA_BACK_BRACHIALIS_TRANSFORM}>
              <path d={BICEPS_AREA_BACK_BRACHIALIS_PATH} />
              <path d={BICEPS_AREA_BACK_BRACHIALIS_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Triceps" transform={TRICEPS_BACK_TRANSFORM}>
              <path d={TRICEPS_BACK_PATH_LEFT} />
              <path d={TRICEPS_BACK_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="triceps-inner" transform={TRICEPS_AREA_BACK_INNER_TRANSFORM}>
              <path d={TRICEPS_AREA_BACK_INNER_PATH} />
              <path d={TRICEPS_AREA_BACK_INNER_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="triceps-medial" transform={TRICEPS_AREA_BACK_MEDIAL_TRANSFORM}>
              <path d={TRICEPS_AREA_BACK_MEDIAL_PATH} />
              <path d={TRICEPS_AREA_BACK_MEDIAL_PATH_RIGHT} />
            </g>
            <g className="muscle-area-region" data-area="triceps-outer" transform={TRICEPS_AREA_BACK_OUTER_TRANSFORM}>
              <path d={TRICEPS_AREA_BACK_OUTER_PATH} />
              <path d={TRICEPS_AREA_BACK_OUTER_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Forearms" transform={FOREARMS_BACK_TRANSFORM}>
              <path d={FOREARMS_BACK_PATH_LEFT} />
              <path d={FOREARMS_BACK_PATH_RIGHT} />
            </g>
            <g className="muscle-region" data-group="Legs" transform={LEGS_BACK_TRANSFORM}>
              <path d={LEGS_BACK_PATH} />
            </g>
            <g className="muscle-area-region" data-area="legs-glutes" transform={LEGS_AREA_BACK_GLUTES_TRANSFORM}>
              <path d={LEGS_AREA_BACK_GLUTES_PATH} />
            </g>
            <g className="muscle-area-region" data-area="legs-hamstring" transform={LEGS_AREA_BACK_HAMSTRING_TRANSFORM}>
              <path d={LEGS_AREA_BACK_HAMSTRING_PATH} />
            </g>
            <g className="muscle-area-region" data-area="legs-calves" transform={LEGS_AREA_BACK_CALVES_TRANSFORM}>
              <path d={LEGS_BACK_PATH} />
            </g>
            {showFocusCornerPoints && backFocusCorners ? (
              <g className="focus-corner-points">
                <circle cx={backFocusCorners.topLeft.x} cy={backFocusCorners.topLeft.y} r="8" />
                <circle cx={backFocusCorners.topRight.x} cy={backFocusCorners.topRight.y} r="8" />
                <circle cx={backFocusCorners.bottomLeft.x} cy={backFocusCorners.bottomLeft.y} r="8" />
                <circle cx={backFocusCorners.bottomRight.x} cy={backFocusCorners.bottomRight.y} r="8" />
              </g>
            ) : null}
          </svg>
        </div>
      </div>
    </div>
  )
}
